import{_ as a,o as e,c as r,a2 as o}from"./chunks/framework.ZhLefgN8.js";const u=JSON.parse('{"title":"期权计算器","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"derivatives/options/options-calculator.md","filePath":"zh-CN/derivatives/options/options-calculator.md"}'),d={name:"derivatives/options/options-calculator.md"};function l(i,t,h,n,s,c){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="期权计算器" tabindex="-1">期权计算器 <a class="header-anchor" href="#期权计算器" aria-label="Permalink to &quot;期权计算器&quot;">​</a></h1><p>期权计算器基于 Black-Scholes 模型，通过调整关键参数，模拟期权的理论价格和希腊字母，帮助用户评估不同市场情景下的期权价值。</p><h2 id="入口" tabindex="-1">入口 <a class="header-anchor" href="#入口" aria-label="Permalink to &quot;入口&quot;">​</a></h2><p>个股详情页 &gt; 期权链 &gt; 点击合约 &gt; 期权详情页 &gt; 期权计算器</p><h2 id="输入参数" tabindex="-1">输入参数 <a class="header-anchor" href="#输入参数" aria-label="Permalink to &quot;输入参数&quot;">​</a></h2><table tabindex="0"><thead><tr><th>参数</th><th>说明</th></tr></thead><tbody><tr><td>标的价格</td><td>正股当前价格，默认取实时市价，可手动修改</td></tr><tr><td>隐含波动率 (%)</td><td>市场对未来波动的预期，默认取当前合约的隐含波动率，可手动修改</td></tr><tr><td>无风险利率 (%)</td><td>无风险收益率，默认取当前利率（如美国国债利率），可手动修改</td></tr><tr><td>初始日期</td><td>计算起始日期，默认为今日，可通过滑动条调整至到期日之前的任意日期</td></tr></tbody></table><blockquote><p>初始日期下方展示从起始日到到期日的剩余天数（如&quot;距到期日 260 天&quot;），方便直观感受时间价值的衰减。</p></blockquote><h2 id="输出结果" tabindex="-1">输出结果 <a class="header-anchor" href="#输出结果" aria-label="Permalink to &quot;输出结果&quot;">​</a></h2><h3 id="期权理论价格" tabindex="-1">期权理论价格 <a class="header-anchor" href="#期权理论价格" aria-label="Permalink to &quot;期权理论价格&quot;">​</a></h3><p>根据上述参数，由 Black-Scholes 公式计算出的期权理论价值，同时展示与当前市场价格的偏差百分比（如 <code>-14.75%</code> 表示理论价格低于市价）。</p><h3 id="希腊字母" tabindex="-1">希腊字母 <a class="header-anchor" href="#希腊字母" aria-label="Permalink to &quot;希腊字母&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字母</th><th>含义</th></tr></thead><tbody><tr><td>Delta</td><td>标的价格变动 1 元时，期权价格的预期变动量；Call 的 Delta 为正，Put 为负</td></tr><tr><td>Gamma</td><td>Delta 本身的变化速度，即标的价格变动 1 元时 Delta 的变化量</td></tr><tr><td>Vega</td><td>隐含波动率每变动 1% 时，期权价格的预期变动量</td></tr><tr><td>Theta</td><td>每过一天，期权价格因时间流逝而减少的金额（时间价值衰减），通常为负值</td></tr><tr><td>Rho</td><td>无风险利率每变动 1% 时，期权价格的预期变动量</td></tr></tbody></table><h2 id="使用场景" tabindex="-1">使用场景 <a class="header-anchor" href="#使用场景" aria-label="Permalink to &quot;使用场景&quot;">​</a></h2><p><strong>情景模拟</strong>：在买入前，调整标的价格，预测正股涨跌对期权价值的影响。</p><p><strong>波动率分析</strong>：修改隐含波动率，评估 IV 压缩或扩张时期权价格的变化（常用于财报前后的判断）。</p><p><strong>时间价值评估</strong>：拖动初始日期滑条，观察随着临近到期日，Theta 如何加速侵蚀期权价值。</p><p><strong>利率敏感度</strong>：对于长期期权（LEAPS），无风险利率的变化影响更显著，可通过 Rho 评估利率风险。</p><h2 id="模型限制与免责说明" tabindex="-1">模型限制与免责说明 <a class="header-anchor" href="#模型限制与免责说明" aria-label="Permalink to &quot;模型限制与免责说明&quot;">​</a></h2><ul><li>计算结果基于 Black-Scholes 模型，仅供参考，不代表实际成交价格。</li><li>实际市场价格受供需、流动性等因素影响，可能与理论价格存在差异。</li><li>点击「查看免责声明」了解更多说明。</li></ul>',19)])])}const b=a(d,[["render",l]]);export{u as __pageData,b as default};
